using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 10, 3, 5);

            // Assert
            Assert.Equal(3, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            // 10 items, 5 per page = 2 pages
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3, 4, 5 }, 10, 1, 5);

            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void Constructor_TotalPages_RoundsUp()
        {
            // 11 items, 5 per page = 3 pages (ceil(11/5) = 3)
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3, 4, 5 }, 11, 1, 5);

            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void Constructor_SinglePage_WhenCountEqualsPageSize()
        {
            // 5 items, 5 per page = 1 page
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3, 4, 5 }, 5, 1, 5);

            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 10, 20, 30 };
            var list = new PaginatedList<int>(items, 30, 1, 10);

            Assert.Equal(3, list.Count);
            Assert.Contains(10, list);
            Assert.Contains(20, list);
            Assert.Contains(30, list);
        }

        [Fact]
        public void Constructor_EmptyList_WorksCorrectly()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);

            Assert.Empty(list);
            Assert.Equal(1, list.PageIndex);
            Assert.Equal(0, list.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_PageOne_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_PageTwo_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            // 10 items, 5 per page = 2 pages, on page 2
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_BeforeLastPage_ReturnsTrue()
        {
            // 10 items, 5 per page = 2 pages, on page 1
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            // 3 items, 5 per page = 1 page, on page 1
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 3, 1, 5);

            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPageOfItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act - page 2, 5 items per page
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.Equal(5, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages); // ceil(20/5) = 4
            Assert.Equal(new List<int> { 6, 7, 8, 9, 10 }, result);
        }

        [Fact]
        public void Create_FirstPage_ContainsFirstItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 15).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.Equal(new List<int> { 1, 2, 3, 4, 5 }, result);
            Assert.True(result.HasNextPage);
            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void Create_LastPage_ContainsRemainingItems()
        {
            // Arrange - 12 items, 5 per page, page 3 has items 11-12
            var source = Enumerable.Range(1, 12).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 5);

            // Assert
            Assert.Equal(new List<int> { 11, 12 }, result);
            Assert.False(result.HasNextPage);
            Assert.True(result.HasPreviousPage);
        }

        [Theory]
        [InlineData(1, 10, 1)]   // 1 item, 10 per page = 1 page
        [InlineData(10, 10, 1)]  // 10 items, 10 per page = 1 page
        [InlineData(11, 10, 2)]  // 11 items, 10 per page = 2 pages
        [InlineData(100, 10, 10)] // 100 items, 10 per page = 10 pages
        [InlineData(0, 10, 0)]   // 0 items = 0 pages
        public void Constructor_CalculatesTotalPages_VariousInputs(int count, int pageSize, int expectedTotalPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            Assert.Equal(expectedTotalPages, list.TotalPages);
        }
    }
}

