using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    [Collection("NotificationQueue")]
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateContext();
            _controller = new NotificationsController(_context);
            TestHelpers.SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            TestHelpers.DrainNotificationQueue();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            // Act
            var result = _controller.Index();

            // Assert
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsType<JsonResult>(result);
            Assert.NotNull(result.Value);

            // Verify the response shape
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.NotNull(countProp);
            Assert.Equal(0, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange - send a notification through a separate NotificationService instance
            // (which shares the same static queue)
            using var service = new NotificationService();
            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsType<JsonResult>(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));

            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(1, (int)countProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_LimitsToTenNotifications()
        {
            // Arrange - add 15 notifications
            using var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
            }

            // Act
            var result = _controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.Equal(10, (int)countProp.GetValue(value));
        }

