using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    [Collection("NotificationQueue")]
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            Helpers.TestHelpers.DrainNotificationQueue();
            _service = new NotificationService();
        }

        public void Dispose()
        {
            _service.Dispose();
            Helpers.TestHelpers.DrainNotificationQueue();
        }

        [Fact]
        public void SendNotification_CreateWithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Student 'John Doe' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateWithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteWithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
        {
            // Arrange & Act
            _service.SendNotification("Instructor", "42", EntityOperation.CREATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Instructor (ID: 42) has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayNameUpdate_GeneratesIdBasedMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "7", EntityOperation.UPDATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student (ID: 7) has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayNameDelete_GeneratesIdBasedMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "99", EntityOperation.DELETE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course (ID: 99) has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_GeneratesIdBasedMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", "  ", EntityOperation.CREATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Student (ID: 1) has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsEntityTypeCorrectly()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course", notification.EntityType);
        }

        [Fact]
        public void SendNotification_SetsEntityIdCorrectly()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("101", notification.EntityId);
        }

        [Fact]
        public void SendNotification_SetsOperationString()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.DELETE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("DELETE", notification.Operation);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "CREATE")]
        [InlineData(EntityOperation.UPDATE, "UPDATE")]
        [InlineData(EntityOperation.DELETE, "DELETE")]
        public void SendNotification_OperationToString_MatchesEnum(EntityOperation operation, string expected)
        {
            // Arrange & Act
            _service.SendNotification("Test", "1", operation);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal(expected, notification.Operation);
        }

        [Fact]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", "John", EntityOperation.CREATE, "AdminUser");

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("AdminUser", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", "John", EntityOperation.CREATE, null);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            // Arrange
            var before = DateTime.Now;

            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var after = DateTime.Now;
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _service.ReceiveNotification();

            // Assert
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_WithItems_ReturnsInFifoOrder()
        {
            // Arrange
            _service.SendNotification("First", "1", EntityOperation.CREATE);
            _service.SendNotification("Second", "2", EntityOperation.UPDATE);

            // Act
            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            // Assert
            Assert.Equal("First", first.EntityType);
            Assert.Equal("Second", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            // Arrange
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Act
            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - MarkAsRead is a no-op for in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllQueued()
        {
            // Arrange & Act
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            // Assert
            var n1 = _service.ReceiveNotification();
            var n2 = _service.ReceiveNotification();
            var n3 = _service.ReceiveNotification();
            var n4 = _service.ReceiveNotification();

            Assert.NotNull(n1);
            Assert.NotNull(n2);
            Assert.NotNull(n3);
            Assert.Null(n4);
        }
    }

    [CollectionDefinition("NotificationQueue")]
    public class NotificationQueueCollection { }
}

