+        /// <summary>
+        /// Drains any stale notifications from parallel controller tests,
+        /// sends a notification, and finds it by matching entityType + entityId + operation.
+        /// This avoids false failures from static queue contamination.
+        /// </summary>
+        private Notification SendAndFind(
+            string entityType, string entityId, string displayName,
+            EntityOperation operation, string userName = null)
+        {
+            // Drain stale entries
+            while (_service.ReceiveNotification() != null) { }
+
+            // Send
+            if (displayName != null)
+                _service.SendNotification(entityType, entityId, displayName, operation, userName);
+            else
+                _service.SendNotification(entityType, entityId, operation, userName);
+
+            // Find our notification (skip any injected by parallel tests)
+            Notification n;
+            while ((n = _service.ReceiveNotification()) != null)
+            {
+                if (n.EntityType == entityType && n.EntityId == entityId &&
+                    n.Operation == operation.ToString())
+                    return n;
+            }
+            return null;
+        }
